counter_attack.test_skeleton:
// Adversarial: dimension without hierarchies key — node count is just measures
#[test]
fn adversarial_ac1_dimension_no_hierarchies() {
    use mqo_concept_graph::ConceptGraph;
    let json = r#"{"measures":[{"unique_name":"m1","name":"R"}],"dimensions":[{"unique_name":"d1","name":"D"}],"calculated_members":[]}""
#;
    let g = ConceptGraph::from_describe_model(json).unwrap();
    assert_eq!(g.node_count(), 1); // only the measure
}
// Adversarial: JSON string value
#[test]
fn adversarial_ac3_json_string() {
    use mqo_concept_graph::ConceptGraph;
    assert!(ConceptGraph::from_describe_model(r#""hello""#).is_err());
}
